INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'2', E'workplace-accommodations-for-people-with-disabil-12252', E'התאמות במקום העבודה לאנשים עם מוגבלויות', E'Workplace Accommodations for People with Disabilities', E'employment', E'employer', E'{any}', E'חובת המעסיק להתאים את מקום העבודה ותנאי העבודה לעובד או מועמד עם מוגבלות לפי צרכיו — התאמות פיזיות, התאמת נהלים, חניה נגישה והחזר הוצאות נסיעה — אלא אם ההתאמה פוגעת במהות התפקיד או מטילה על המעסיק נטל בלתי סביר.', E'Employers must adapt the workplace and work conditions to a disabled worker or job candidate (physical adaptations, procedure changes, accessible parking, travel reimbursement), unless the accommodation harms the essence of the role or imposes an unreasonable burden.', E'חוק שוויון זכויות לאנשים עם מוגבלות, התשנ"ח-1998', E'https://www.kolzchut.org.il/he/התאמות_במקום_העבודה_לאנשים_עם_מוגבלויות', E'{12252}', E'0.9309', E'0.88', E'[-0.030151367,-0.024902344,-0.026733398,-0.0066833496,0.056152344,7.343292e-05,0.011108398,-0.014892578,-0.016113281,0.004638672,0.032470703,-1.4424324e-05,0.00017929077,0.048339844,-0.032714844,-0.005554199,-0.025634766,0.026733398,-0.029418945,0.046875,0.0077209473,0.036376953,0.01171875,0.032226562,-0.010437012,-0.025756836,0.06689453,-0.056152344,0.032958984,-0.0064697266,-0.012817383,0.09423828,-0.020874023,0.016723633,0.028320312,-0.055908203,0.028930664,0.030883789,0.008300781,0.026611328,-0.06982422,0.010498047,0.042236328,0.0115356445,-0.0021362305,-0.03491211,0.024169922,0.036621094,0.063964844,-0.010437012,0.018554688,-0.024291992,0.00029563904,0.0099487305,0.0119018555,-0.022094727,0.008666992,-0.015014648,0.021484375,-0.038330078,-0.019165039,-0.018066406,-0.061767578,-0.0053710938,-0.012084961,-0.040527344,0.06201172,-0.032714844,-0.04248047,-0.024536133,-0.013000488,-