INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'3', E'rights-based-on-medical-disability-percentage-in-10484', E'זכויות בגין נכות רפואית ללא התניה בקצבת נכות', E'Rights Based on Medical Disability Percentage (Independent of Disability Pension)', E'disability_general', E'bituach_leumi', E'{general_disability}', E'דף-שער הממפה זכאויות הניתנות לפי אחוזי נכות רפואית (שנקבעו ע"י הביטוח הלאומי או רשות המסים), ללא תלות בקבלת קצבת נכות: החל מ-20% — שיקום מקצועי; מ-40% — הנחות בעמלות בנק וקהילה תומכת; מ-60% — תג חניה ואגרת רישוי מופחתת; מ-75%/80% — פטורים שונים; 90%/100% — פטור ממס הכנסה והנחה במס רכישה; ובנוסף הנחות בארנונה ובתחבורה ציבורית.', E'A hub page mapping a ladder of benefits granted by recognized medical-disability percentage (set by Bituach Leumi or the Tax Authority), independent of receiving a disability pension — from vocational rehab (20%) through parking and license-fee reductions (60%) to income-tax and purchase-tax exemptions (90–100%), plus property-tax and public-transport discounts.', NULL, E'https://www.kolzchut.org.il/he/זכויות_בגין_נכות_רפואית_ללא_התניה_בקצבת_נכות', E'{10484}', E'0.9254', E'0.78', E'[-0.059814453,-0.013366699,-0.006134033,0.00793457,0.0056152344,0.004211426,0.039794922,0.022216797,0.034423828,0.0028533936,0.0023651123,-0.0032958984,-0.013366699,-0.017211914,-0.032226562,-0.013183594,-0.0016098022,0.000541687,-0.014282227,0.006652832,0.03540039,0.041259766,0.003692627,0.016601562,-0.0234375,-0.01574707,0.007080078,-0.028930664,0.010070801,-0.02331543,-0.03564453,0.04736328,-0.048339844,0.017822266,-0.037597656,-0.024414062,-0.016967773,-0.003250122,-0.014343262,-0.0126953125,-0.045166016,0.037109375,-0.012329102,-0.004180908,0.016357422,-0.02368164,0.03173828,0.023803711,0.021240234,-0.036376953,0.03955078,-0.046142578,0.016967773,0.0