INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'7', E'adequate-representation-of-people-with-disabilit-11296', E'ייצוג הולם לאנשים עם מוגבלויות במקומות עבודה', E'Adequate Representation of People with Disabilities in the Workplace', E'employment', E'employer', E'{any}', E'מעסיק של 25 עובדים ומעלה חייב לפעול לייצוג הולם של אנשים עם מוגבלות, בין היתר באמצעות התאמות במקום העבודה והעדפה מתקנת (בכישורים דומים). במקום עבודה עם 100 עובדים ומעלה ייצוג הולם הוא לפחות 3% עובדים עם מוגבלות, וחובה למנות אחראי לקידום התעסוקה.', E'Employers of 25+ must pursue adequate representation of people with disabilities — via workplace accommodations and affirmative preference (at comparable qualifications). At 100+ employees the target is ≥3% workers with disabilities, plus a mandatory employment officer.', E'חוק שוויון זכויות לאנשים עם מוגבלות, התשנ"ח-1998, סעיף 9; צו ההרחבה לעידוד ולהגברת התעסוקה של אנשים עם מוגבלות', E'https://www.kolzchut.org.il/he/ייצוג_הולם_לאנשים_עם_מוגבלויות_במקומות_עבודה', E'{11296}', E'0.9145', E'0.85', E'[-0.032714844,-0.036621094,-0.01586914,0.020751953,0.055419922,-0.0008277893,0.020141602,-0.0021362305,0.009643555,0.017089844,0.0074157715,0.00793457,0.022216797,0.034423828,-0.029418945,0.009094238,-0.023925781,0.020385742,-0.026733398,0.061035156,0.021850586,0.052490234,0.009033203,0.029052734,-0.028320312,-0.0037078857,0.05053711,-0.044189453,0.03466797,-0.00014972687,-0.0015029907,0.080566406,-0.012451172,0.0058288574,0.030517578,-0.053466797,0.011352539,0.021118164,-0.036621094,0.0049438477,-0.04736328,0.0033569336,0.017700195,0.010314941,-0.012573242,-0.012573242,0.0007362366,0.047607422,0.029663086,-0.005004883,0.0078125,-0.0073242188,-0.015258789,0.044677734,0.017333984,0.00025558472,-0.019042969,-0.031982422,-0.007232666,-0.0052490234,-0.0036773682,-0