INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'8', E'housing-adaptation-assistance-for-people-with-mo-3507', E'סיוע בהתאמת תנאי דיור לאנשים המוגבלים בניידות', E'Housing Adaptation Assistance for People with Mobility Limitations', E'housing', E'ministry_of_housing', E'{any}', E'משרד הבינוי והשיכון מסייע במימון שינויים ושיפוצים החיוניים לתפקוד ולניידות בתוך הדירה ובדרכי הגישה אליה, כשילוב של מענק והלוואה (או הלוואה בלבד) לפי מספר הנפשות, החדרים וההכנסה. לדיירי דיור ציבורי — מענק מלא.', E'The Ministry of Construction & Housing funds changes essential for functioning and mobility inside the home and its access routes, as a grant+loan mix (or loan only) depending on household size, rooms and income. Public-housing tenants receive a full grant.', NULL, E'https://www.kolzchut.org.il/he/סיוע_בהתאמת_תנאי_דיור_לאנשים_המוגבלים_בניידות', E'{3507}', E'0.9096', E'0.85', E'[-0.04248047,-0.024658203,0.01361084,-0.009460449,-0.006652832,-0.029418945,0.03564453,-0.061279297,-0.0126953125,-0.047851562,0.0625,0.014526367,0.04272461,0.03466797,-0.037597656,-0.006225586,-0.018432617,0.04272461,0.00014686584,0.06933594,0.03564453,-0.040039062,-0.01928711,0.07910156,0.009399414,-0.028198242,0.07861328,-0.021728516,0.059570312,-0.006378174,0.0019836426,0.068847656,-0.051513672,0.008544922,0.007019043,-0.012268066,-0.006713867,0.017089844,-0.034179688,0.012329102,-0.010864258,0.014892578,0.053710938,0.032958984,-0.013122559,-0.009155273,0.038330078,0.024169922,0.021484375,-0.03466797,0.018676758,-0.02758789,-0.012145996,-0.02758789,0.0053710938,-0.031982422,0.003967285,-0.03125,-0.010620117,-0.045898438,-0.01361084,0.0025024414,0.013000488,0.011474609,-0.0049743652,-0.037109375,0.067871094,-0.031982422,-0.055664062,0.008239746,0.001045227,-0.036865234,-0.0007286072,-0.016113281,-0.00680542,