INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'10', E'making-accessibility-adaptations-in-a-shared-con-12489', E'ביצוע התאמות לאנשים עם מוגבלויות בבית משותף', E'Making Accessibility Adaptations in a Shared (Condominium) Building', E'housing', E'other', E'{any}', E'זכותו של בעל דירה (או בן משפחה/שוכר שהוא אדם עם מוגבלות) לבצע התאמות ברכוש המשותף לשם נגישות בטוחה ועצמאית לדירה, בכפוף לאישור מקצועי ולכך שההתאמה אינה מונעת שימוש סביר משאר הדיירים. הביצוע על חשבון בעל הדירה, אך ניתן לקבל סיוע במימון ממשרד השיכון.', E'The right of an apartment owner (or a disabled family member/tenant) to make adaptations in the building''s common property for safe, independent access to the dwelling, subject to a professional certificate and not preventing other owners'' reasonable use. Costs fall on the owner, but housing-ministry funding is available.', E'חוק המקרקעין; חוק שוויון זכויות לאנשים עם מוגבלות', E'https://www.kolzchut.org.il/he/ביצוע_התאמות_לאנשים_עם_מוגבלויות_בבית_משותף', E'{12489}', E'0.8992', E'0.82', E'[-0.022338867,-0.033447266,-0.016601562,0.0025634766,-0.0029907227,-0.05078125,0.035888672,-0.021362305,-0.016601562,-0.02709961,0.05029297,0.022460938,0.0022583008,0.04663086,-0.030029297,-0.0021362305,-0.021972656,0.01953125,-0.019165039,0.072265625,-0.013549805,0.0032806396,0.0030212402,0.044189453,0.02355957,-0.008605957,0.071777344,-0.080566406,0.04248047,-0.0024871826,0.0051879883,0.10449219,-0.036621094,0.028930664,0.01965332,-0.05908203,0.013977051,0.025268555,-0.0234375,0.005340576,-0.055908203,-0.010681152,0.034423828,0.037353516,0.005004883,-0.0138549805,0.041992188,0.06933594,0.013244629,-0.008850098,0.048095703,0.0061950684,-0.028808594,-0.013671875,0.011779785,0.005554199,-0.017333984,-0.030639648,0.010253906,-0.017944336,-0.05053711,-0.030029297,-0.01104736