INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'11', E'state-co-funding-of-workplace-accommodations-for-2871', E'השתתפות המדינה במימון התאמות במקום העבודה לעובדים עם מוגבלות', E'State Co-funding of Workplace Accommodations for Workers with Disabilities', E'employment', E'ministry_of_labor', E'{any}', E'המדינה משתתפת במימון הוצאות מעסיק על התאמות סביבת העבודה לעובד עם מוגבלות. ההשתתפות ניתנת כהלוואה עומדת ההופכת למענק כעבור שנה. הסכומים נקבעים לפי סוג ההתאמה וגודל המעסיק, עם מסלול מימון מוגדל להתאמות מקרקעין לעובדים עם מוגבלות ניידות גבוהה.', E'The state co-funds an employer''s spending on adapting the work environment for a disabled worker. Given as a standing loan that becomes a grant after a year, with amounts by adaptation type and employer size, plus enhanced funding for real-estate adaptations for workers with high mobility disability.', E'תקנות שוויון זכויות לאנשים עם מוגבלות (השתתפות המדינה במימון התאמות)', E'https://www.kolzchut.org.il/he/השתתפות_המדינה_במימון_התאמות_במקום_העבודה_לעובדים_עם_מוגבלות', E'{2871}', E'0.8991', E'0.82', E'[0.00015544891,-0.026367188,-0.008178711,-0.002746582,0.029541016,-0.03955078,0.059570312,-0.024291992,-0.03515625,-0.0009498596,0.031982422,-0.022094727,0.036621094,0.028198242,-0.048095703,-0.020263672,-0.026367188,0.040039062,-0.020507812,0.015991211,0.022460938,0.030151367,-0.033203125,0.026245117,0.010192871,-0.030761719,0.07714844,-0.07421875,0.02758789,-0.01586914,-0.016723633,0.068359375,-0.0031433105,0.01965332,0.036621094,0.016723633,-0.008483887,0.024780273,-0.04638672,0.004119873,-0.04248047,0.0047302246,0.04638672,0.017700195,0.017944336,0.02355957,0.03930664,0.0042419434,0.023071289,-0.020874023,0.032226562,0.010864258,0.01361084,-0.033447266,-0.024414062,-0.033935547,0.007293701,-0.030151367,-0.0013046265,-0.023559