INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'12', E'general-disability-pension-and-associated-benefi-4840', E'קצבת נכות כללית והטבות נלוות', E'General Disability Pension and Associated Benefits', E'financial_support', E'bituach_leumi', E'{general_disability}', E'קצבה חודשית מהמוסד לביטוח לאומי לבוגרים שליקוי גופני, שכלי או נפשי פוגע ב-50% לפחות מכושרם להשתכר (או בכושר עקרת בית לתפקד במשק הבית). הזכאות מהווה שער למגוון הטבות נלוות — דיור, תחבורה, הקלות מס ובריאות.', E'A monthly Bituach Leumi pension for adults whose physical, intellectual or mental impairment reduces earning capacity by at least 50%. Eligibility is the gateway to a wide range of associated benefits in housing, transport, taxation and health.', E'חוק הביטוח הלאומי', E'https://www.kolzchut.org.il/he/קצבת_נכות_והטבות_נלוות', E'{4840}', E'0.8968', E'0.85', E'[-0.040771484,-0.040039062,-0.018920898,0.009765625,0.0024414062,0.024169922,0.029907227,0.032714844,0.009887695,0.0035247803,0.015136719,0.014953613,0.025878906,-0.020385742,-0.036132812,-0.011291504,-0.028930664,0.008117676,-0.003616333,0.041748047,0.00793457,0.0010986328,0.02368164,0.024047852,-0.025024414,-0.008056641,0.0234375,-0.040771484,-0.009277344,0.0061035156,0.015136719,0.07080078,-0.009521484,0.021850586,0.0016021729,-0.05834961,0.009399414,-0.006652832,-0.0039978027,0.0060424805,-0.026245117,0.026245117,0.026000977,0.04272461,0.027832031,-0.013122559,0.021728516,0.036132812,0.012634277,-0.010070801,0.030517578,-0.022583008,0.035888672,0.029663086,0.005004883,0.012512207,-0.0011138916,0.025268555,0.026000977,-0.057861328,-0.037109375,-0.018188477,-0.013427734,0.0079956055,-0.01586914,-0.027954102,0.057373047,-0.014282227,-0.028930664,-0.052001953,0.00039863586,-0.039794922,0.0064697266,-0.03173828,0.049804688,-0.013305664,-0.043701172