INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'14', E'prohibition-of-employment-discrimination-against-4099', E'איסור אפליית עובד בשל היותו אדם עם מוגבלות', E'Prohibition of Employment Discrimination Against People with Disabilities', E'employment', E'employer', E'{any}', E'החוק אוסר על מעסיק להפלות עובד עם מוגבלות (הכשיר לבצע את העבודה) בקבלה לעבודה, תנאים, קידום, הכשרה ופיטורים, וכן אוסר אפליה של בן משפחה של אדם עם מוגבלות. המעסיק מחויב בהתאמות, ובית הדין רשאי לפסוק פיצוי עד 50,000 ₪ ללא הוכחת נזק.', E'The law bars employers from discriminating against a disabled worker (fit to do the job) in hiring, conditions, promotion, training and dismissal, and against a worker who is a family member of a disabled person. Employers must provide accommodations; courts may award up to ₪50,000 compensation without proof of damage.', E'חוק שוויון זכויות לאנשים עם מוגבלות, התשנ"ח-1998', E'https://www.kolzchut.org.il/he/איסור_אפליית_עובד_בשל_היותו_אדם_עם_מוגבלות', E'{4099}', E'0.8957', E'0.85', E'[-0.017211914,0.00046157837,-0.024658203,-0.016113281,0.012451172,-0.012756348,0.010070801,0.028930664,0.0012130737,0.01953125,0.037597656,-0.0019073486,-0.013000488,0.07519531,-0.014770508,0.003250122,-0.056640625,-0.018798828,-0.029663086,0.037597656,0.008544922,-0.007080078,-0.008056641,0.036132812,-0.04272461,-0.018920898,0.07421875,-0.044921875,-0.0016479492,0.00037956238,-0.011169434,0.08300781,-0.025878906,0.02746582,0.043945312,-0.076171875,0.0067443848,0.017578125,0.0017547607,0.021850586,-0.08691406,0.014526367,0.021972656,-0.033691406,0.0019378662,-0.027832031,0.01953125,0.028320312,0.046875,0.009033203,0.03149414,-0.012145996,0.0024871826,0.028320312,0.017578125,0.010437012,-0.032226562,-0.0234375,0.016723633,-0.0390625,-0.03540039,-0.032226562,-0.0017547607,-0.010070801,-0.0