INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'17', E'standing-loan-for-new-vehicle-taxes-under-the-mo-3218', E'הלוואה עומדת למימון מסים לרכב חדש במסגרת גמלת ניידות', E'Standing Loan for New-Vehicle Taxes under the Mobility Benefit', E'mobility', E'bituach_leumi', E'{any}', E'במסגרת גמלת ניידות, רוכשי רכב חדש זכאים להלוואה עומדת למימון מלא או חלקי של המסים על הרכב (לפי ''רכב קובע''), בתנאי שהרכב כולל את האבזרים שקבע המכון הרפואי לבטיחות בדרכים. שיעור ההלוואה נקבע לפי אחוז המוגבלות בניידות וקיומו של רישיון נהיגה.', E'Under the mobility benefit, buyers of a new vehicle receive a standing loan covering full or partial vehicle taxes (per a ''reference vehicle''), provided the car includes the accessories set by the Medical Institute for Road Safety. The loan rate depends on the mobility-disability percentage and whether the person holds a driving licence.', E'הסכם הניידות (ביטוח לאומי)', E'https://www.kolzchut.org.il/he/הלוואה_עומדת_למימון_מסים_לרכב_חדש_במסגרת_גמלת_ניידות', E'{3218}', E'0.8929', E'0.85', E'[-0.028442383,-0.029418945,0.017822266,-0.049072266,-0.0047912598,-0.041259766,0.079589844,0.00049209595,0.014404297,0.009643555,0.0053100586,-0.009277344,-0.019042969,0.023803711,-0.02758789,-0.022583008,0.0039978027,-0.014831543,-0.0022125244,0.012145996,-0.0045166016,-0.017700195,-0.06201172,0.021362305,-0.0016326904,-0.036621094,0.051513672,-0.005645752,0.030029297,-0.0011749268,0.0052490234,0.075683594,-0.013793945,-0.01361084,0.017700195,-0.0036468506,-0.008178711,0.0058288574,-0.056884766,-0.013305664,-0.080566406,-0.012573242,-0.03540039,0.0050964355,-0.005493164,-0.042236328,-0.014282227,0.033203125,-0.0079956055,-0.044921875,-0.017822266,-0.0009498596,0.013000488,-0.027954102,-0.014404297,-0.0058288574,0.024291992,-0.018066406,0.02319336,-0.030639648,-0.053