INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'19', E'accessibility-for-people-with-disabilities-in-hi-18564', E'נגישות לאנשים עם מוגבלות במוסד להשכלה גבוהה', E'Accessibility for People with Disabilities in Higher-Education Institutions', E'education', E'other', E'{any}', E'מוסדות להשכלה גבוהה (מוכרי מל"ג ומכללות להוראה) מחויבים בנגישות פיזית ובהנגשת השירות לסטודנטים ומועמדים עם מוגבלות: דרכי גישה רציפות, חניות נגישות סמוכות, מקומות ישיבה מותאמים, הנגשת סיורים ומרכז תמיכה ייעודי. הזכות ניתנת לרוב באופן אוטומטי.', E'Recognized higher-education institutions must provide physical and service accessibility to students and candidates with disabilities: continuous accessible routes, nearby accessible parking, adapted seating, accessible field trips and a dedicated support center. Generally provided automatically.', E'חוק שוויון זכויות לאנשים עם מוגבלות; תקנות נגישות במוסדות להשכלה גבוהה', E'https://www.kolzchut.org.il/he/נגישות_לאנשים_עם_מוגבלות_במוסד_להשכלה_גבוהה', E'{18564}', E'0.8918', E'0.8', E'[-0.029418945,-0.011047363,-0.036376953,0.024047852,0.025146484,0.006866455,0.03149414,-0.020507812,0.011047363,-0.02746582,0.037353516,0.014160156,-0.057128906,0.03491211,0.033935547,0.026733398,-0.025512695,0.03100586,-0.015991211,0.05029297,0.005004883,0.026855469,0.012878418,-0.01953125,0.019042969,0.00019550323,0.0390625,-0.07470703,0.052490234,0.0115356445,-0.032470703,0.06591797,-0.061767578,0.01159668,0.024658203,-0.011779785,0.012512207,0.012756348,-0.017333984,0.007385254,-0.05419922,-0.0008010864,0.0049438477,0.059570312,0.0067749023,0.01373291,0.009460449,0.026367188,-0.018676758,-0.036865234,-0.0024414062,-0.0034332275,-0.022949219,0.030029297,-0.016967773,-0.017822266,0.013427734,-0.04248047,-0.014770508,-0.010009766,-0.022094727,0.0018615723,-0.028320312,0.01074