INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'20', E'eligibility-for-work-injury-disability-pension-o-1965', E'זכאות לקצבת נכות או למענק נכות לנפגעי עבודה', E'Eligibility for Work-Injury Disability Pension or Grant', E'work_injury', E'bituach_leumi', E'{work_injury}', E'נכי עבודה שעקב פגיעה בעבודה נפגע כושרם לעבוד זכאים לקצבת נכות מעבודה או למענק חד-פעמי, לפי דרגת הנכות: 20%-100% יציבה — קצבה חודשית; 9%-100% זמנית — קצבה לתקופה; 9%-19% יציבה — מענק חד-פעמי; מתחת ל-9% — אין זכאות. ההכנסה אינה משפיעה על שיעור הקצבה.', E'Work-injured people whose earning capacity was harmed are entitled to a work-injury disability pension or a one-time grant by disability degree: 20–100% stable — monthly pension; 9–100% temporary — time-limited pension; 9–19% stable — one-time grant; below 9% — none. Income does not affect the pension amount.', E'חוק הביטוח הלאומי (ביטוח נפגעי עבודה)', E'https://www.kolzchut.org.il/he/זכאות_לקצבת_נכות_או_למענק_נכות_לנפגעי_עבודה', E'{1965}', E'0.8915', E'0.85', E'[-0.024536133,-0.020385742,-0.025024414,0.018920898,0.031982422,0.0012130737,0.02746582,0.042236328,0.01171875,-0.018310547,-0.01586914,-0.013244629,0.022583008,-0.012390137,-0.056640625,-0.011779785,-0.016967773,-0.010131836,-0.009765625,0.045654297,0.03955078,0.028686523,0.044433594,0.013549805,-0.02319336,-0.008728027,0.018188477,-0.055419922,0.024291992,0.014221191,0.0045166016,0.095703125,-0.03857422,0.0072631836,0.0021362305,-0.018798828,0.007019043,0.0033874512,0.0032806396,-0.0013885498,-0.07128906,0.027832031,0.0021209717,0.0012283325,0.04638672,-0.007659912,0.03491211,0.03930664,0.036865234,-0.0051879883,0.036132812,-0.022216797,0.03515625,0.047851562,0.004760742,-0.00592041,-0.0071105957,0.007751465,-0.004119873,-0.05810547,-0.014831543,-0.013061523,-0.02355957,0.021484375,-0.02478