INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'21', E'income-tax-exemption-for-people-with-disabilitie-2957', E'פטור ממס הכנסה לאנשים עם נכות', E'Income-Tax Exemption for People with Disabilities', E'taxation', E'tax_authority', E'{any}', E'פטור ממס הכנסה על הכנסה מיגיעה אישית ושלא מיגיעה אישית, עד לתקרות שנתיות, למי שנקבעה להם נכות מזכה (כ-90% ומעלה, או 100% על ליקוי אחד; בחישוב משוקלל נדרש ליקוי אחד של 40% לפחות) למשך 185 יום לפחות, לפי אחד מחוקי הנכות. ניתן לקבל החזרי מס עד 6 שנים רטרואקטיבית.', E'Income-tax exemption on personal-exertion and non-personal-exertion income up to annual ceilings, for those with a qualifying disability (~90%+, or 100% on a single impairment; weighted 90% requires one impairment ≥40%) set for at least 185 days. Tax refunds available up to 6 years retroactively.', E'פקודת מס הכנסה, סעיף 9(5)', E'https://www.kolzchut.org.il/he/פטור_ממס_הכנסה_לאנשים_עם_נכות', E'{2957}', E'0.89', E'0.85', E'[-0.053222656,0.00592041,0.0040283203,0.010437012,0.010314941,-0.039794922,0.028930664,0.05834961,-0.0046691895,-0.0234375,0.055419922,-0.014099121,0.026611328,-0.03930664,-0.048828125,-0.010314941,-0.013977051,-0.004699707,-0.021972656,0.01361084,0.051513672,0.018066406,0.011962891,0.03173828,-0.041015625,-0.016845703,0.016601562,-0.029663086,-0.006652832,-0.010559082,0.028564453,0.05078125,-0.029174805,0.03149414,-0.04663086,-0.02734375,-0.029296875,-0.002670288,-0.0046081543,-0.015991211,-0.03857422,0.012268066,-0.00046920776,0.011474609,0.009155273,0.002166748,0.018920898,0.0040893555,0.04321289,-0.030517578,0.009216309,-0.0035705566,0.01953125,0.024902344,-0.016601562,0.012878418,0.013122559,-0.01928711,0.020629883,-0.06201172,-0.018188477,-0.019165039,0.005859375,0.020507812,-0.006652832,-0.013183594,0.06982422,-0.0014953613,-0.007080078,-0.0378