INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'24', E'reduced-vehicle-licence-fee-for-a-disabled-parki-14454', E'אגרת רישוי מופחתת לרכב עם תג חניה לנכה', E'Reduced Vehicle-Licence Fee for a Disabled-Parking-Badge Vehicle', E'transportation', E'ministry_of_transport', E'{any}', E'בעלי תג חניה לנכה זכאים לאגרת רישוי מופחתת בסך 28 ₪ בלבד עבור רכב המשויך לתג (10 ₪ למשרתי מילואים פעילים), בתנאי שהרכב רשום על שם הנכה/בן זוגו/האפוטרופוס ואינו משמש לעסק. ניתן גם החזר רטרואקטיבי של החלק היחסי ששולם.', E'Holders of a disabled-parking badge pay a reduced vehicle-licence fee of just ₪28 for the badge''s vehicle (₪10 for active reservists), provided the car is registered to the disabled person/spouse/guardian and not used for business. A pro-rata retroactive refund is available.', NULL, E'https://www.kolzchut.org.il/he/אגרת_רישוי_מופחתת_לרכב_עם_תג_חניה_לנכה', E'{14454}', E'0.8835', E'0.85', E'[-0.05517578,-0.048095703,0.022705078,-0.03515625,-0.022583008,-0.032226562,0.05444336,0.015625,0.0234375,-0.0073547363,0.020751953,-0.029663086,0.01574707,0.053222656,0.00491333,-0.0068969727,-0.006958008,-0.014282227,0.00074386597,0.008300781,-0.0126953125,-0.006164551,-0.06347656,0.045654297,-0.046142578,-0.018432617,0.03955078,-0.022216797,0.038085938,-0.026611328,-0.00078201294,0.049072266,-0.04296875,-0.032226562,0.028198242,-0.029785156,-0.0039978027,-0.0025024414,-0.055908203,-0.014892578,-0.057128906,-0.0060424805,0.0033416748,-0.031982422,0.0234375,-0.04345703,0.026977539,0.02331543,-0.027832031,-0.055664062,-0.012329102,-0.004486084,0.0054626465,-0.030273438,-0.013977051,-0.024414062,0.014831543,-0.018188477,0.016723633,-0.036621094,-0.029052734,-0.014404297,-0.010864258,-0.008361816,-0.014404297,-0.06982422,0.053222656,0.007751465,-0.01928711,-0.0054626465,-0.046875,-0.03027343