INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'26', E'recognition-of-a-hostile-action-terror-injury-11698', E'הכרה בפגיעת איבה (פעולת איבה)', E'Recognition of a Hostile-Action (Terror) Injury', E'hostile_action', E'bituach_leumi', E'{hostile_action}', E'כדי לקבל זכויות ופיצויים על נזקי גוף שנגרמו בפעולת איבה, יש להכיר באירוע כפגיעת איבה. תביעה לפגיעה פיסית/נפשית מוגשת לביטוח הלאומי (בתוך שנה מהפגיעה), ולנזקי רכוש לרשות המסים. ההכרה היא השער לתגמול טיפול רפואי (תט"ר) ולתגמול נכות.', E'To receive rights and compensation for bodily harm from a hostile act, the event must be recognized as a hostile-action injury. Physical/mental claims go to Bituach Leumi (within a year of injury), property claims to the Tax Authority. Recognition is the gateway to medical-treatment and disability allowances.', E'חוק התגמולים לנפגעי פעולות איבה', E'https://www.kolzchut.org.il/he/הכרה_בפגיעת_איבה_(פעולת_איבה)', E'{11698}', E'0.8823', E'0.78', E'[-0.025390625,-0.052734375,0.019042969,0.03125,-0.006072998,-0.008056641,0.019042969,0.060546875,0.05029297,-0.0030517578,0.030639648,0.017700195,-0.006011963,0.027954102,-0.0068359375,-0.0059509277,-0.014099121,-0.03930664,0.018920898,0.029785156,0.01361084,-0.03564453,-0.010253906,0.04638672,-0.013916016,0.0036468506,-0.0022583008,-0.036132812,0.0039978027,-0.0028686523,0.04272461,0.06933594,-0.032714844,0.015197754,0.029663086,-0.09863281,-0.016601562,0.00793457,0.008239746,0.006591797,-0.04296875,0.025512695,-0.020263672,-0.0038604736,0.010192871,-0.038085938,0.018798828,0.044189453,0.060058594,-0.040039062,0.042236328,-0.012084961,-0.0015945435,-0.001121521,-0.01940918,0.021362305,0.020263672,0.017944336,-0.0030670166,-0.059326172,-0.032958984,-0.033203125,0.008239746,0.0063476562,0.022338867,-0.053222656,0.053466797,-0.01586914,0.0079956055