INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'27', E'property-tax-arnona-discount-for-people-with-dis-4033', E'הנחה בארנונה לנכים', E'Property-Tax (Arnona) Discount for People with Disabilities', E'taxation', E'municipality', E'{any}', E'הרשויות המקומיות מעניקות לנכים הנחות בארנונה לפי אוכלוסיית הזכאות: נכות רפואית 90%+ — עד 40%; מקבלי קצבת נכות כללית 75%+ — עד 80%; נכי צה"ל/נפגעי איבה/משטרה/שב"ס — 66.66%; מקבלי קצבת זיקנה לנכה — 100%. חלק מההנחות מוגבלות לשטח דירה מרבי.', E'Local authorities grant property-tax discounts to people with disabilities by eligibility group: 90%+ medical disability — up to 40%; recipients of a 75%+ general disability pension — up to 80%; IDF/hostile-action/police/prison-service disabled — 66.66%; disabled old-age-pension recipients — 100%. Some discounts are capped by apartment area.', E'תקנות הסדרים במשק המדינה (הנחה מארנונה)', E'https://www.kolzchut.org.il/he/הנחה_בארנונה_לנכים', E'{4033}', E'0.8813', E'0.82', E'[-0.05126953,-0.041503906,-0.049316406,0.014282227,-0.03955078,0.07373047,0.05883789,0.016967773,0.024658203,0.0008621216,-0.022949219,-0.012451172,0.013977051,0.0119018555,-0.041259766,-0.0054016113,-0.003967285,0.020629883,-0.020141602,0.026611328,0.024902344,0.0035247803,-0.03491211,0.03491211,-0.002822876,0.0022277832,0.00061798096,-0.032714844,-0.003250122,0.004180908,0.000869751,0.07080078,-0.09667969,0.018432617,0.004486084,-0.07373047,-0.001701355,-0.0046081543,-0.03173828,-0.016967773,-0.01159668,0.014099121,-0.013671875,-0.013305664,0.041992188,-0.03930664,0.060058594,0.078125,0.012573242,-0.044677734,0.017333984,0.018188477,-0.0066833496,0.03857422,-0.041992188,-0.0045776367,0.010864258,-0.016235352,-0.0048828125,-0.0043640137,-0.03100586,0.004211426,0.013183594,0.016479492,-0.016479492,-0.07421875,0.064453125,0.00