INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'31', E'exemption-from-mortgage-and-lease-registration-f-20354', E'פטור מאגרת רישום משכנתא ואגרת רישום שכירות לאנשים עם נכות', E'Exemption from Mortgage- and Lease-Registration Fees for People with Disabilities', E'taxation', E'other', E'{any}', E'אנשים שנקבעה להם נכות — ובכללם במפורש קטועי יד או רגל ומשותקים — פטורים מתשלום אגרה על רישום משכנתא ועל רישום שכירות. הזכאות חלה גם על נכי צה"ל, נפגעי איבה, נפגעי עבודה ובעלי 100% נכות, ועל בני זוגם.', E'People with a recognized disability — explicitly including arm/leg amputees and the paralyzed — are exempt from mortgage- and lease-registration fees, as are IDF/hostile-action/work-injury disabled and those with 100% disability, and their spouses.', E'תקנות המקרקעין (אגרות)', E'https://www.kolzchut.org.il/he/פטור_מאגרת_רישום_משכנתא_ואגרת_רישום_שכירות_לאנשים_עם_נכות', E'{20354}', E'0.86', E'0.85', E'[-0.05419922,-0.018798828,-0.029907227,-0.014831543,-0.022705078,-0.072265625,0.036376953,0.014282227,0.02319336,-0.030029297,0.05078125,0.00037956238,0.046875,0.0023040771,-0.03100586,-0.012084961,0.006286621,-0.01586914,-0.014038086,-0.017944336,0.033935547,0.016723633,-0.020751953,0.022705078,-0.040283203,-0.029663086,0.016479492,-0.024536133,0.016357422,0.0033416748,-0.010681152,0.08154297,0.009155273,-0.015014648,-0.010620117,-0.034179688,-0.0018920898,0.01965332,-0.026977539,-0.01159668,-0.03515625,0.032226562,0.012268066,0.024658203,-0.00982666,-0.014282227,0.036865234,0.044433594,-0.0037841797,-0.022460938,0.0138549805,-0.028320312,0.0017700195,0.07519531,-0.011779785,-0.021728516,-0.0069885254,-0.018066406,0.045166016,-0.059814453,-0.053466797,-0.016845703,0.010131836,-0.022216797,-0.017822266,-0.05859375,0.06689453,0.016845703,-0.029052734,-0.022827148,-0.030883789,-0.026