INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'32', E'limb-prostheses-for-hostile-action-casualties-wi-21350', E'תותבות יד ורגל לנפגעי פעולות איבה קטועי גפיים', E'Limb Prostheses for Hostile-Action Casualties with Amputations', E'prosthetics_aids', E'bituach_leumi', E'{hostile_action}', E'נפגעי פעולת איבה קטועי גפיים זכאים ל-2 תותבות מותאמות אישית לכל איבר שנקטע: בקטיעת רגל — תותבת לשימוש רגיל ותותבת לרחצה; בקטיעת יד — תותבת פונקציונלית ותותבת אסתטית. כולל החלפות, תיקונים, אימון פיזיותרפי, ובמקרים מסוימים נסיעה להתקנה בחו"ל.', E'Hostile-action casualties with amputations are entitled to 2 custom prostheses per amputated limb (leg: everyday + bathing; arm: functional + aesthetic), plus replacements, repairs, physiotherapy training, and in some cases travel abroad for fitting.', E'חוק התגמולים לנפגעי פעולות איבה', E'https://www.kolzchut.org.il/he/תותבות_יד_ורגל_לנפגעי_פעולות_איבה_קטועי_גפיים', E'{21350}', E'0.86', E'0.85', E'[-0.023803711,-0.083496094,0.0005187988,0.03125,0.032958984,-0.04638672,0.05883789,0.032958984,0.05883789,-0.017944336,0.0146484375,0.01586914,-0.0058898926,0.002105713,-0.045166016,-0.0063476562,-0.033935547,-0.018554688,-0.011108398,0.005218506,0.022338867,-0.029663086,-0.0010070801,0.03564453,-0.01928711,0.039794922,0.009094238,-0.01159668,0.010253906,-0.020629883,-0.025634766,0.061767578,-0.02355957,-0.034423828,0.03491211,-0.045166016,0.024902344,0.026489258,-0.020874023,-0.011962891,-0.048828125,0.0019989014,0.037353516,0.022094727,0.037353516,-0.038085938,0.0042419434,0.07519531,0.0087890625,-0.03515625,0.07910156,0.001914978,0.012268066,0.103515625,0.0003452301,0.011291504,0.023803711,0.033447266,0.000579834,-0.040283203,-0.01953125,-0.018188477,0.011291504,0.0012817383,-0.014343262,-0.03857422,0.06738281,-0.016479492,0.0053710938,-0.0272