INSERT INTO public.rights (id, slug, name_he, name_en, domain, authority, injury_cause, description_he, summary_en, legal_basis, source_url, source_doc_ids, retrieval_score, extraction_confidence, embedding, snapshot_date, notes, created_at) VALUES (E'1', E'supported-employment-for-people-with-disabilitie-14215', E'תעסוקה נתמכת לאנשים עם מוגבלויות', E'Supported Employment for People with Disabilities', E'employment', E'ministry_of_labor', E'{general_disability}', E'שירות בחינם (מטעם משרד העבודה, בגישה דרך המחלקה לשירותים חברתיים) המסייע לאנשים עם מוגבלות להשתלב בשוק העבודה הפתוח: בניית תוכנית שיקום, סדנאות והכשרה פרטנית, השמה במקום עבודה וליווי מתמשך של העובד והמעסיק.', E'A free service helping people with disabilities integrate into the open labor market via a rehabilitation plan, training workshops, job placement and ongoing coaching of both worker and employer.', NULL, E'https://www.kolzchut.org.il/he/תעסוקה_נתמכת_לאנשים_עם_מוגבלויות', E'{14215}', E'0.9373', E'0.9', E'[-0.040283203,-0.014404297,-0.0036468506,0.010864258,0.052490234,0.008056641,0.014587402,-0.06298828,0.01550293,0.00970459,0.053466797,-0.0030212402,-0.02319336,0.037109375,-0.016113281,0.011779785,-0.05883789,0.041992188,-0.003326416,0.071777344,0.013183594,0.059570312,-0.0032196045,0.036376953,-0.031982422,-0.016845703,0.046142578,-0.04272461,0.020385742,-0.015075684,-0.011291504,0.068359375,-0.03491211,-0.03100586,0.012756348,-0.021362305,-0.0016098022,-0.0020751953,-0.040771484,0.005340576,-0.024291992,0.018188477,0.049316406,0.012756348,-0.0029144287,0.012878418,0.017333984,0.030517578,0.03857422,-0.036132812,0.041259766,-0.043945312,0.0087890625,0.037597656,0.031982422,-0.056396484,0.0011367798,0.010864258,0.009216309,-0.031982422,-0.012634277,-0.029541016,-0.020507812,0.014709473,-0.011962891,-0.03515625,0.06738281,-0.024047852,-0.028808594,-0.009338379,-0.002166748,-0.025024414,0.001373291,-0.034179688,-0.0068359375,0.016357422,0.01977539,0.051513672,0.057617188,0.040771484,0.022094727,-0.02