INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'3', E'2', E'service_in_kind', E'התאמה פיזית של מקום העבודה ושל עמדת העבודה האישית, כולל הנגשה ורכישת אמצעי עזר, וכן התאמת נהלים ושעות עבודה.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'המעסיק פטור אם ההתאמה פוגעת במהות התפקיד או מטילה נטל בלתי סביר.', E'0.9');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'4', E'2', E'priority_access', E'הקצאת מקום חניה נגיש לעובד בעל תג חניה לנכה, אם קיימים במקום העבודה לפחות 3 מקומות חניה לעובדים.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'מותנה בתג חניה לנכה ובקיום לפחות 3 מקומות חניה לעובדים.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'5', E'2', E'transport', E'החזר הוצאות נסיעה ברכב פרטי כאשר המוגבלות מונעת שימוש בשירות ההסעות של המעסיק.', E'variable', NULL, NULL, NULL, E'ILS', E'per_use', E'מבוסס על פסיקה; תלוי בכך שהמוגבלות מונעת שימוש בהסעה המאורגנת.', E'0.65');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'6', E'2', E'legal_protection', E'הגנה מפני אפליה: ניתן להגיש תביעה לבית הדין לעבודה או תלונה לנציבות שוויון זכויות; בית הדין רשאי לפסוק פיצויים גם ללא הוכחת נזק.', E'n/a', NULL, NULL, NULL, E'n/a', E'n/a', NULL, E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'7', E'3', E'rehabilitation', E'שיקום מקצועי וסיוע בלימודים החל מ-20% נכות רפואית לצמיתות.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'הנכות נקבעה על-ידי הביטוח הלאומי.', E'0.75');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'8', E'3', E'tax_exemption', E'פטורים והקלות במס (פטור ממס הכנסה, הנחה במס רכישה, נקודת זיכוי) לבעלי אחוזי נכות גבוהים (כ-90%-100%).', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'סף ותנאים משתנים לפי ההטבה הספציפית.', E'0.7');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'9', E'4', E'monthly_allowance', E'קצבה חודשית לפי רמת תלות: 50% (1,771 ₪), 112% (4,099 ₪), 188% (6,542 ₪), 235% (8,313 ₪) — נכון ל-2024.', E'range', NULL, E'1771', E'8313', E'ILS', E'monthly', E'השיעור נקבע לפי מידת התלות בזולת והצורך בהשגחה.', E'0.9');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'10', E'4', E'monthly_allowance', E'תוספת למונשמים: מקבלי קצבה בשיעור 188% לפחות הזקוקים למכונת הנשמה כל היממה זכאים לתוספת של 9,813 ₪ (2024).', E'fixed', E'9813', NULL, NULL, E'ILS', E'monthly', E'מותנה בקצבה ≥188% ובשימוש במכונת הנשמה כל היממה.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'11', E'4', E'monthly_allowance', E'תוספת להורים לילד עד גיל 3: 1,106 ₪ לילד, עד שני ילדים (עד 2,212 ₪) — 2024.', E'up_to_max', NULL, E'1106', E'2212', E'ILS', E'monthly', E'מקבלי קצבת שר"מ בכל הרמות עם ילד/ים עד גיל 3.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'12', E'5', E'legal_protection', E'הכרה כנכה צה"ל/כוחות הביטחון — מעמד המקנה זכאות לתגמולי נכות ולסל זכויות השיקום של אגף השיקום במשרד הביטחון.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'ההכרה מותנית בקשר סיבתי בין הפגיעה/המחלה לשירות.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'13', E'5', E'one_time_grant', E'החזר עלות הוצאת התיק הרפואי מקופת החולים — עד 800 ₪.', E'up_to_max', NULL, NULL, E'800', E'ILS', E'one_time', E'החזר מטעם אגף השיקום.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'14', E'6', E'legal_protection', E'קביעת שכר מינימום מותאם כאחוז משכר המינימום הרגיל, לפי אבחון כושר העבודה — מאפשרת העסקה חוקית התואמת ליכולת העובד.', E'percentage', NULL, NULL, NULL, E'percent', E'ongoing', E'האחוז נקבע באבחון תפקודי במקום העבודה, לאחר לפחות 3 חודשי העסקה.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'15', E'7', E'legal_protection', E'זכות לייצוג הולם: העדפה מתקנת בקבלה ובקידום (בכישורים דומים) וביצוע התאמות; אכיפה בבית הדין לעבודה ובנציבות שוויון זכויות, כולל פיצויים גם ללא הוכחת נזק.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'במקום עבודה עם 100 עובדים ומעלה היעד הוא לפחות 3% עובדים עם מוגבלות.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'16', E'8', E'one_time_grant', E'סיוע (מענק+הלוואה) עד 65,000 ₪ עבור שינויים פנימיים או חיצוניים בדירה החיוניים לניידות ולתפקוד.', E'up_to_max', NULL, NULL, E'65000', E'ILS', E'one_time', E'תמהיל המענק/הלוואה (90/10, 60/40, 30/70, 0/100) נקבע לפי נפשות, חדרים והכנסה; לדיירי דיור ציבורי מענק מלא.', E'0.9');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'17', E'8', E'one_time_grant', E'סיוע עד 130,000 ₪ להתקנת מעלון.', E'up_to_max', NULL, NULL, E'130000', E'ILS', E'one_time', E'בתנאי שהזכאי התגורר בבית לפני שהחל להיעזר בכיסא גלגלים והמעלון הוא הפתרון הבלעדי לבעיית הניידות בבית.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'18', E'9', E'fee_exemption', E'פטור מתשלום דמי ביטוח לאומי בתקופת הזכאות לקצבה. (דמי ביטוח בריאות בסך 116 ₪ (2024) עדיין ינוכו ממי שאין לו הכנסה נוספת.)', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'אוטומטי למי שאינם עובדים; שכירים מגישים אישור שנתי למעסיק. ניתן רק אם הקצבה משולמת בפועל.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'19', E'10', E'legal_protection', E'זכות לבצע התאמות נגישות ברכוש המשותף (כגון רמפה, מעקה, הרחבת מעבר), גם במקרים מסוימים על אף התנגדות דיירים (בכפוף להחלטת המפקח על רישום המקרקעין).', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'נדרשת הודעה מוקדמת (40 יום) לוועד/דיירים; בחלק מהמקרים נדרשת הסכמת דיירים.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'20', E'11', E'one_time_grant', E'השתתפות במימון התאמות (פיזיות, ציוד, מבדקי קבלה, ליווי ועוד): עד 19,000 ₪ (עד 25 עובדים), 17,000 ₪ (26-200), 15,000 ₪ (מעל 200), בכפוף להשתתפות עצמית של המעסיק. ניתנת כהלוואה עומדת ההופכת למענק לאחר שנה.', E'up_to_max', NULL, NULL, E'19000', E'ILS', E'one_time', E'השתתפות עצמית 1,000/3,000/5,000 ₪ לפי גודל המעסיק; לא מאושר מתחת ל-1,000 ₪.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'21', E'11', E'one_time_grant', E'מימון מוגדל עד 60,000 ₪ לכלל ההתאמות לעובד — כשנדרשות התאמות מקרקעין לעובד עם 75% מוגבלות בניידות, או ציוד מחשוב מיוחד לעובד עיוור/לקוי ראייה.', E'up_to_max', NULL, NULL, E'60000', E'ILS', E'one_time', E'בכפוף להשתתפות עצמית של 5,000 ₪ לפחות.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'22', E'11', E'one_time_grant', E'הדרכה ראשונית למעסיק: עד 3,000 ₪ לעובד או 95% מהעלות (הנמוך), ללא תלות במספר העובדים.', E'up_to_max', NULL, NULL, E'3000', E'ILS', E'one_time', E'במהלך 6 החודשים הראשונים להעסקה.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'23', E'12', E'monthly_allowance', E'קצבת נכות כללית חודשית, שגובהה תלוי בדרגת אי-הכושר ובתלויים. (סכומים מתעדכנים; אינם מופיעים בדף-השער.)', E'variable', NULL, NULL, NULL, E'ILS', E'monthly', E'ניתן להמשיך ולקבלה (בהפחתה) למקבלים שהחלו לעבוד.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'24', E'13', E'rehabilitation', E'אבחון והכוונה תעסוקתית ומימון לימודי תואר או מקצוע במסגרת שיקום מקצועי.', E'variable', NULL, NULL, NULL, E'ILS', E'ongoing', E'ההיקף נקבע בתוכנית שיקום אישית.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'25', E'14', E'legal_protection', E'איסור אפליה בכל שלבי ההעסקה; זכות תביעה למעסיק המפלה ופיצוי שבית הדין רשאי לפסוק עד 50,000 ₪ ללא הוכחת נזק, וכן סיוע מנציבות שוויון זכויות.', E'up_to_max', NULL, NULL, E'50000', E'ILS', E'one_time', E'הפיצוי נתון לשיקול דעת בית הדין לעבודה.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'26', E'15', E'service_in_kind', E'שירותי סיעוד (מטפל אישי, מרכז יום, מוצרי ספיגה, לחצן מצוקה, שירותי כביסה ועוד) או קבלת חלק מהגמלה בכסף, ב-6 רמות לפי מידת התלות.', E'variable', NULL, NULL, NULL, E'ILS', E'monthly', E'הרכב השירותים ורמתם נקבעים לפי מבחן תלות (ADL).', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'27', E'16', E'priority_access', E'הכשרה או הקצאה של מקום חניה לנכה ברכוש המשותף, והתאמתו (סימון, תמרור) — ההתאמה לאחר ההקצאה אינה דורשת הסכמת דיירים.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'ההקצאה/ההכשרה דורשת הסכמת 60% מבעלי הדירות; ניתן לפנות למפקח על רישום המקרקעין במקרה של התנגדות בלתי סבירה.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'28', E'17', E'loan', E'הלוואה עומדת למימון מסי הרכב: 100% למי שנקבעו להם 80%-100% מוגבלות בניידות; שיעור השווה לאחוז המוגבלות למי שנקבעו 60%-79%. ההלוואה הופכת בפועל למענק כל עוד עומדים בתנאי ההתחייבות.', E'percentage', NULL, NULL, E'100', E'percent', E'one_time', E'אין לרכוש את הרכב לפני אישור ההלוואה; קיימות תקופות מינימום להחלפת רכב (42/48/60 חודשים).', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'29', E'18', E'housing', E'רכישת דירה נגישה ומותאמת (בתוספת שיפוץ והתאמה) עבור הזכאי, שמתווספת למלאי הדיור הציבורי.', E'n/a', NULL, NULL, NULL, E'n/a', E'one_time', E'בכפוף לתקציב; הזכאות מבוטלת למי שמסרבים לגור בדירה שאיתרו ונרכשה.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'30', E'19', E'service_in_kind', E'נגישות פיזית והנגשת שירות: דרך גישה רציפה מחניה/תחנה/מדרכה לבניינים, חניות נגישות סמוכות, מקומות ישיבה מותאמים בכיתות, הנגשת סיורים (כולל הסעה מותאמת), ומרכז תמיכה לליווי וסיוע.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'חלק מההתאמות האישיות דורשות בקשה מראש לפי נהלי המוסד.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'31', E'20', E'monthly_allowance', E'קצבת נכות חודשית מעבודה לבעלי דרגת נכות יציבה 20%-100% (או זמנית 9%-100% לתקופה שנקבעה). ההכנסה אינה משפיעה על שיעור הקצבה.', E'variable', NULL, NULL, NULL, E'ILS', E'monthly', E'הסכומים מפורטים בדף ''קצבת נכות ומענק נכות לנפגעי עבודה''.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'32', E'20', E'one_time_grant', E'מענק נכות חד-פעמי לבעלי דרגת נכות יציבה 9%-19%.', E'variable', NULL, NULL, NULL, E'ILS', E'one_time', E'מתחת ל-9% אין זכאות.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'33', E'21', E'tax_exemption', E'פטור ממס הכנסה על הכנסה מיגיעה אישית עד תקרה שנתית של 445,200 ₪ (2024; ו-684,000 ₪ לנכי צה"ל/נפגעי איבה עם נכות ל-365 יום ומעלה). לנכות ל-185–364 יום התקרה 81,960 ₪.', E'up_to_max', NULL, NULL, E'684000', E'ILS', E'annual', E'מתחת לתקרה — פטור מלא; מעליה — פטור עד התקרה. החזרי מס עד 6 שנים אחורה.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'34', E'22', E'rehabilitation', E'אשפוז שיקומי אינטנסיבי לשיפור התפקודים המוטוריים והקוגניטיביים והגדלת העצמאות, לתקופה של עד 3 חודשים (ניתן להאריך באישור ועדה מקצועית של קופת החולים).', E'n/a', NULL, NULL, NULL, E'n/a', E'one_time', E'במימון קופת החולים; פצע לחץ או הזנה בזונדה אינם מונעים קבלת שיקום.', E'0.85');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'35', E'23', E'housing', E'הקצאת דירה בדיור הציבורי. רתוקים לכיסא גלגלים זכאים לדירה צמודת-קרקע או בבניין עם מעלית, ולדירה גדולה יותר (3 חדרים עד 4 נפשות; 4 חדרים מ-5 נפשות).', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'תעודת הזכאות תקפה ל-4 שנים; הזכאות נבחנת ביישוב המגורים.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'36', E'24', E'fee_exemption', E'אגרת רישוי שנתית מופחתת בסך 28 ₪ (10 ₪ למשרתי מילואים פעילים) לרכב המשויך לתג החניה.', E'fixed', E'28', NULL, NULL, E'ILS', E'annual', E'ניתן לרכב אחד בלבד אם משויכים שניים לתג; ניתן החזר רטרואקטיבי.', E'0.9');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'37', E'25', E'loan', E'הלוואה מקרן ההלוואות לרכישת רכב פרטי: ברכב ראשון חלק הופך למענק בתום 5 שנים; בהחלפה — 20% משווי הרכב להחזר מלא בתשלומים חודשיים.', E'percentage', E'20', NULL, NULL, E'percent', E'one_time', E'הרכב משועבד לטובת הביטוח הלאומי (למעט זכאי רכב לאבזרים מיוחדים שבחרו ברכב פרטי).', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'38', E'26', E'legal_protection', E'הכרה כנפגע פעולת איבה — מעמד המקנה זכאות לתגמול טיפול רפואי (תט"ר), לתגמול נכות ולפיצויים, וכן לסיוע משפטי חינם בנושאי הביטוח הלאומי.', E'n/a', NULL, NULL, NULL, E'n/a', E'ongoing', E'תביעה לפגיעה פיסית/נפשית תוך שנה מהפגיעה; לרוב הרשויות פונות ביוזמתן.', E'0.8');
INSERT INTO public.benefits (id, right_id, benefit_type, description_he, amount_type, amount_value, amount_min, amount_max, currency, frequency, conditions_note, confidence) VALUES (E'39', E'27', E'discount', E'הנחה בארנונה: עד 40% לבעלי נכות רפואית 90%+; עד 80% למקבלי קצבת נכות כללית 75%+; 66.66% לנכי צה"ל/נפגעי איבה/משטרה/שב"ס; 100% למקבלי קצבת זיקנה לנכה.', E'range', NULL, E'33', E'100', E'percent', E'annual', E'השיעור והשטח המרבי תלויים באוכלוסיית הזכאות ובמספר הנפשות בדירה.', E'0.85');
